import{_ as e,c as s,o as n,a as t}from"./app.606ab571.js";const C=JSON.parse('{"title":"Testing","description":"","frontmatter":{},"headers":[{"level":2,"title":"Overview","slug":"overview","link":"#overview","children":[]},{"level":2,"title":"Unit Tests","slug":"unit-tests","link":"#unit-tests","children":[{"level":3,"title":"What is tested","slug":"what-is-tested","link":"#what-is-tested","children":[]},{"level":3,"title":"Running unit tests","slug":"running-unit-tests","link":"#running-unit-tests","children":[]}]},{"level":2,"title":"Integration Tests","slug":"integration-tests","link":"#integration-tests","children":[{"level":3,"title":"Infrastructure","slug":"infrastructure","link":"#infrastructure","children":[]},{"level":3,"title":"Integration test coverage","slug":"integration-test-coverage","link":"#integration-test-coverage","children":[]},{"level":3,"title":"Running integration tests","slug":"running-integration-tests","link":"#running-integration-tests","children":[]}]},{"level":2,"title":"Test Design Decisions","slug":"test-design-decisions","link":"#test-design-decisions","children":[]}],"relativePath":"testing.md"}'),a={name:"testing.md"},o=t(`<h1 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-hidden="true">#</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-hidden="true">#</a></h2><p>The test suite is split into two projects \u2014 unit tests for domain logic and integration tests for the full application stack including the database, outbox, and HTTP pipeline.</p><h2 id="unit-tests" tabindex="-1">Unit Tests <a class="header-anchor" href="#unit-tests" aria-hidden="true">#</a></h2><p>Located in <code>Ticketing.UnitTests</code>. Tests domain aggregates and entities in isolation with no infrastructure dependencies.</p><h3 id="what-is-tested" tabindex="-1">What is tested <a class="header-anchor" href="#what-is-tested" aria-hidden="true">#</a></h3><p><strong>Reservation</strong> \u2014 state transition rules:</p><ul><li><code>Confirm()</code> sets status to <code>Confirmed</code> when <code>Pending</code></li><li><code>Confirm()</code> throws when already <code>Confirmed</code></li><li><code>Cancel()</code> and <code>Expire()</code> set correct status from <code>Pending</code></li></ul><p><strong>Payment</strong> \u2014 state transition rules:</p><ul><li><code>Complete()</code> sets status to <code>Completed</code> when <code>Pending</code></li><li><code>Complete()</code> throws when already <code>Completed</code></li></ul><p><strong>ScreeningSeat</strong> \u2014 seat lifecycle:</p><ul><li><code>Reserve()</code> transitions from <code>Available</code> to <code>Reserved</code></li><li><code>Reserve()</code> throws when already <code>Reserved</code> or <code>Sold</code></li><li><code>MarkAsSold()</code> transitions from <code>Reserved</code> to <code>Sold</code></li><li><code>MarkAsSold()</code> throws when not <code>Reserved</code></li><li><code>Release()</code> transitions back to <code>Available</code></li><li><code>Release()</code> throws when already <code>Sold</code></li></ul><p><strong>Screening</strong> \u2014 aggregate invariants:</p><ul><li>Cannot be created without seats</li><li><code>GetSeat()</code> returns correct seat by ID</li><li><code>GetSeat()</code> throws when seat not found</li></ul><p><strong>Hall</strong> \u2014 aggregate invariants:</p><ul><li>Cannot be created without seats</li><li><code>AddSeat()</code> succeeds for valid seats</li><li><code>AddSeat()</code> throws on duplicate row/column</li><li><code>AddSeat()</code> throws when seat belongs to another hall</li><li><code>GetSeat()</code> returns correct seat, throws when not found</li></ul><p><strong>Seat</strong> \u2014 construction invariants:</p><ul><li>Row cannot be empty or whitespace</li><li>Column must be greater than 0</li></ul><h3 id="running-unit-tests" tabindex="-1">Running unit tests <a class="header-anchor" href="#running-unit-tests" aria-hidden="true">#</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">dotnet </span><span style="color:#82AAFF;">test</span><span style="color:#A6ACCD;"> Ticketing.UnitTests</span></span>
<span class="line"></span></code></pre></div><h2 id="integration-tests" tabindex="-1">Integration Tests <a class="header-anchor" href="#integration-tests" aria-hidden="true">#</a></h2><p>Located in <code>Ticketing.IntegrationTests</code>. Tests the full application stack against a real PostgreSQL database using <code>WebApplicationFactory</code>.</p><h3 id="infrastructure" tabindex="-1">Infrastructure <a class="header-anchor" href="#infrastructure" aria-hidden="true">#</a></h3><p><strong><code>CustomWebApplicationFactory</code></strong> \u2014 replaces the production <code>DbContext</code> registration with a test database connection:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">Host=localhost;Port=5433;Database=ticketing_test</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p><strong><code>TestDatabaseFixture</code></strong> \u2014 shared across all tests in the <code>Integration</code> collection. On startup it runs <code>EnsureDeleted</code> + <code>Migrate</code> to guarantee a clean schema. Between each test <code>ResetDatabase()</code> truncates all tables and re-seeds test data.</p><p><strong><code>IntegrationTestBase</code></strong> \u2014 base class for all integration tests. Provides:</p><ul><li><code>Client</code> \u2014 <code>HttpClient</code> pointed at the test server</li><li><code>CreateDbContext()</code> \u2014 fresh <code>DbContext</code> for assertions</li><li><code>RunOutboxProcessorOnce()</code> \u2014 manually triggers the outbox processor</li><li><code>GetService&lt;T&gt;()</code> \u2014 resolves any registered service from DI</li><li><code>WaitForAsync()</code> \u2014 polls a condition with timeout, running the outbox processor on each iteration</li></ul><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki"><code><span class="line"><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">async</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Task</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">WaitForAsync</span><span style="color:#89DDFF;">(</span><span style="color:#FFCB6B;">Func</span><span style="color:#89DDFF;">&lt;</span><span style="color:#FFCB6B;">Task</span><span style="color:#89DDFF;">&lt;bool&gt;&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">condition</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">int</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">timeoutMs</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">5000</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#F78C6C;">var</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">deadline</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> DateTime</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">UtcNow</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">AddMilliseconds</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">timeoutMs</span><span style="color:#89DDFF;">);</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">while</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">DateTime</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">UtcNow </span><span style="color:#89DDFF;">&lt;</span><span style="color:#A6ACCD;"> deadline</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">if</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#F78C6C;">await</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">condition</span><span style="color:#89DDFF;">())</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">return</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#F78C6C;">await</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">RunOutboxProcessorOnce</span><span style="color:#89DDFF;">();</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#F78C6C;">await</span><span style="color:#A6ACCD;"> Task</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">Delay</span><span style="color:#89DDFF;">(</span><span style="color:#F78C6C;">100</span><span style="color:#89DDFF;">);</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">throw</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">TimeoutException</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Condition not met within timeout</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">);</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>This is the key utility for testing async event chains \u2014 it drives the outbox manually rather than relying on the background worker timer.</p><h3 id="integration-test-coverage" tabindex="-1">Integration test coverage <a class="header-anchor" href="#integration-test-coverage" aria-hidden="true">#</a></h3><p><strong>Outbox correctness:</strong></p><ul><li>Creating a reservation writes an outbox message with the correct type and payload</li><li>A failed reservation writes no outbox message</li><li>Running the outbox processor creates a payment from a <code>ReservationCreated</code> message</li></ul><p><strong>Idempotency:</strong></p><ul><li>Handling <code>ReservationCreated</code> twice for the same reservation creates only one payment (verified via <code>DuplicateEntityException</code> handling)</li></ul><p><strong>Duplicate reservation:</strong></p><ul><li>A second reservation attempt for the same seat fails and produces no outbox message</li></ul><p><strong>Validation:</strong></p><ul><li>Empty seat list returns a failure response</li><li>Duplicate seat IDs in the same request returns a failure response</li></ul><p><strong>Concurrency:</strong></p><ul><li>50 concurrent reservation attempts for the same seat result in exactly 1 success, 1 reservation row, and 1 outbox message</li></ul><p><strong>Full end-to-end flow:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">POST /api/Reservations</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2192 outbox: ReservationCreated \u2192 Payment created (Pending)</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2192 POST /api/payments/webhook (completed)</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2192 outbox: PaymentCompleted \u2192 Reservation confirmed</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2192 outbox: ReservationConfirmed \u2192 Seats marked as Sold</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p>Asserts final state: <code>Reservation = Confirmed</code>, <code>Seat = Sold</code>, <code>Payment = Completed</code>, no dead-lettered messages.</p><h3 id="running-integration-tests" tabindex="-1">Running integration tests <a class="header-anchor" href="#running-integration-tests" aria-hidden="true">#</a></h3><p>Requires a running PostgreSQL instance on port <code>5433</code>. Start it with Docker:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">docker run -d --name ticketing-test-db \\</span></span>
<span class="line"><span style="color:#A6ACCD;">  -e POSTGRES_PASSWORD=postgres \\</span></span>
<span class="line"><span style="color:#A6ACCD;">  -e POSTGRES_DB=ticketing_test \\</span></span>
<span class="line"><span style="color:#A6ACCD;">  -p 5433:5432 postgres:16</span></span>
<span class="line"></span></code></pre></div><p>Then:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">dotnet </span><span style="color:#82AAFF;">test</span><span style="color:#A6ACCD;"> Ticketing.IntegrationTests</span></span>
<span class="line"></span></code></pre></div><h2 id="test-design-decisions" tabindex="-1">Test Design Decisions <a class="header-anchor" href="#test-design-decisions" aria-hidden="true">#</a></h2><p><strong>Manual outbox driving</strong> \u2014 the background worker polls every 200ms which makes tests slow and timing-dependent. <code>RunOutboxProcessorOnce()</code> and <code>WaitForAsync()</code> give deterministic control over when events are processed.</p><p><strong>Per-test DB reset</strong> \u2014 each test gets a clean slate via <code>TRUNCATE ... CASCADE</code> + re-seed rather than transactions or recreating the database, which keeps tests fast while ensuring isolation.</p><p><strong>No mocking in integration tests</strong> \u2014 the full infrastructure stack runs against a real database. This catches issues that mocks would hide, like EF Core concurrency token behavior and outbox serialization.</p><p><strong>Unit tests test invariants, not workflows</strong> \u2014 domain state transition rules are covered in unit tests. The integration tests cover the wiring between layers.</p>`,54),l=[o];function i(r,c,p,d,u,g){return n(),s("div",null,l)}const y=e(a,[["render",i]]);export{C as __pageData,y as default};
